option.value:
:root {
    --popup-width-min: 320px;
    --popup-height-min: 240px;
    --popup-bg: #23272e;
    --popup-border-radius: 16px;
    --popup-shadow: 0 4px 24px rgba(0,0,0,0.25);
    --popup-header-bg: #2c313a;
    --popup-title-color: #fff;
    --popup-content-color: #d1d5db;
    --popup-padding: 24px;
}

.container {
    min-width: var(--popup-width-min);
    min-height: var(--popup-height-min);
    background-color: var(--popup-bg);
    border-radius: var(--popup-border-radius);
    box-shadow: var(--popup-shadow);
    padding: var(--popup-padding);
    flex-direction: column;
    align-items: stretch;
    justify-content: flex-start;
    display: flex;
}

.header {
    background-color: var(--popup-header-bg);
    border-radius: var(--popup-border-radius) var(--popup-border-radius) 0 0;
    padding: 12px 0 12px 0;
    margin-bottom: 16px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.title {
    color: var(--popup-title-color);
    font-size: 1.5em;
    font-weight: bold;
    letter-spacing: 0.02em;
    text-align: center;
}

.content {
    color: var(--popup-content-color);
    font-size: 1.1em;
    line-height: 1.5;
    text-align: left;
    margin-top: 8px;
}

/* ArmyStorageGlobal.uss */

.container {
    width: 30%;
    height: 60%;
    align-items: flex-start;
    justify-content: flex-start;
    flex-direction: column;
    position: absolute;
    left: 0;
    top: 20%;
}

.header {
    width: 100%;
    margin-bottom: 12px;
}

.header__title {
    font-size: 20px;
    font-weight: bold;
    margin-bottom: 8px;
}

.content {
    width: 100%;
    flex-direction: column;
    gap: 8px;
}

.army-storage {
    display: flex;
    flex-direction: row;
    align-items: center;
    width: 100%;
    height: 40px;
    margin-bottom: 6px;
}

.army-storage__label {
    flex: 1 1 60%;
    font-size: 16px;
    text-align: left;
}

.army-storage__value {
    flex: 1 1 40%;
    font-size: 16px;
    text-align: right;
}
